import os
import secrets
import json
import requests
from functools import wraps
from flask import Flask, redirect, request, session, url_for, jsonify, abort
from urllib.parse import urlencode
from jose import jwt, JWTError


app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_hex(32))

# OIDC Configuration - set these via environment variables
OIDC_CONFIG = {
    "issuer": os.environ.get("OIDC_ISSUER", "https://your-idp.example.com"),
    "authorization_endpoint": os.environ.get(
        "OIDC_AUTH_ENDPOINT",
        "https://your-idp.example.com/authorize"
    ),
    "jwks_uri": os.environ.get(
        "OIDC_JWKS_URI",
        "https://your-idp.example.com/.well-known/jwks.json"
    ),
    "client_id": os.environ.get("OIDC_CLIENT_ID", "your-client-id"),
    "redirect_uri": os.environ.get(
        "OIDC_REDIRECT_URI",
        "http://localhost:5000/callback"
    ),
}

_jwks_cache = None


def get_jwks():
    """Fetch and cache the JWKS from the identity provider."""
    global _jwks_cache
    if _jwks_cache is None:
        response = requests.get(OIDC_CONFIG["jwks_uri"], timeout=10)
        response.raise_for_status()
        _jwks_cache = response.json()
    return _jwks_cache


def validate_id_token(id_token_raw):
    """
    Validate the ID token signature, claims, and nonce.
    Returns decoded claims if valid, raises on failure.
    """
    jwks = get_jwks()

    try:
        # Decode header to find the key ID
        unverified_header = jwt.get_unverified_header(id_token_raw)
    except JWTError as e:
        raise ValueError(f"Invalid token header: {e}")

    # Find the matching key
    rsa_key = None
    for key in jwks.get("keys", []):
        if key["kid"] == unverified_header.get("kid"):
            rsa_key = key
            break

    if rsa_key is None:
        raise ValueError("Unable to find matching signing key in JWKS")

    try:
        claims = jwt.decode(
            id_token_raw,
            rsa_key,
            algorithms=["RS256"],
            audience=OIDC_CONFIG["client_id"],
            issuer=OIDC_CONFIG["issuer"],
        )
    except JWTError as e:
        raise ValueError(f"Token validation failed: {e}")

    # Validate nonce to prevent replay attacks
    expected_nonce = session.get("oidc_nonce")
    if not expected_nonce:
        raise ValueError("No nonce found in session - possible session fixation")
    if claims.get("nonce") != expected_nonce:
        raise ValueError("Nonce mismatch - possible token replay attack")

    return claims


def login_required(f):
    """Decorator to require authentication for routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        return f(*args, **kwargs)
    return decorated_function


@app.route("/")
def index():
    """Public landing page."""
    if "user" in session:
        return redirect(url_for("dashboard"))
    return (
        "<h1>Internal Admin Dashboard</h1>"
        '<p><a href="/login">Login with SSO</a></p>'
    )


@app.route("/login")
def login():
    """Initiate the OIDC authentication flow."""
    # Generate nonce and state for security
    nonce = secrets.token_urlsafe(32)
    state = secrets.token_urlsafe(32)

    # Store in session for validation on callback
    session["oidc_nonce"] = nonce
    session["oidc_state"] = state

    params = {
        "client_id": OIDC_CONFIG["client_id"],
        "redirect_uri": OIDC_CONFIG["redirect_uri"],
        "scope": "openid",
        "response_type": "id_token",
        "nonce": nonce,
        "state": state,
        "response_mode": "fragment",
    }

    authorization_url = (
        f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    )
    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """
    Handle the OIDC callback.

    With response_type=id_token, the token is returned in the URL fragment
    (after #), which is not sent to the server. We serve a small page that
    extracts it client-side and posts it to our token processing endpoint.
    """
    return """
    <!DOCTYPE html>
    <html>
    <head><title>Authenticating...</title></head>
    <body>
        <p>Completing authentication, please wait...</p>
        <script>
            // The id_token is in the URL fragment (after #)
            const fragment = window.location.hash.substring(1);
            const params = new URLSearchParams(fragment);
            const idToken = params.get('id_token');
            const state = params.get('state');

            if (idToken) {
                // POST the token to the server for validation
                const form = document.createElement('form');
                form.method = 'POST';
                form.action = '/process_token';

                const tokenInput = document.createElement('input');
                tokenInput.type = 'hidden';
                tokenInput.name = 'id_token';
                tokenInput.value = idToken;
                form.appendChild(tokenInput);

                const stateInput = document.createElement('input');
                stateInput.type = 'hidden';
                stateInput.name = 'state';
                stateInput.value = state;
                form.appendChild(stateInput);

                document.body.appendChild(form);
                form.submit();
            } else {
                const error = params.get('error');
                const errorDesc = params.get('error_description');
                document.body.innerHTML = '<h2>Authentication Failed</h2>' +
                    '<p>' + (errorDesc || error || 'Unknown error') + '</p>' +
                    '<p><a href="/">Try again</a></p>';
            }
        </script>
        <noscript>
            <p>JavaScript is required for authentication. Please enable it.</p>
        </noscript>
    </body>
    </html>
    """


@app.route("/process_token", methods=["POST"])
def process_token():
    """Validate the ID token and establish a session."""
    id_token_raw = request.form.get("id_token")
    state = request.form.get("state")

    if not id_token_raw:
        abort(400, description="No ID token received")

    # Validate state parameter
    expected_state = session.pop("oidc_state", None)
    if not expected_state or state != expected_state:
        abort(403, description="Invalid state parameter - possible CSRF attack")

    try:
        claims = validate_id_token(id_token_raw)
    except ValueError as e:
        app.logger.warning(f"Token validation failed: {e}")
        abort(403, description=f"Token validation failed: {e}")

    # Clean up nonce from session after successful validation
    session.pop("oidc_nonce", None)

    # Store user info in session
    session["user"] = {
        "sub": claims.get("sub"),
        "email": claims.get("email"),
        "name": claims.get("name", claims.get("preferred_username", "")),
        "groups": claims.get("groups", []),
    }

    app.logger.info(
        f"User authenticated: {session['user'].get('email', session['user']['sub'])}"
    )

    # Redirect to the originally requested page or dashboard
    next_url = session.pop("next_url", url_for("dashboard"))
    return redirect(next_url)


@app.route("/dashboard")
@login_required
def dashboard():
    """Protected admin dashboard."""
    user = session["user"]
    return (
        f"<h1>Admin Dashboard</h1>"
        f"<p>Welcome, {user.get('name', user['sub'])}!</p>"
        f"<p>Email: {user.get('email', 'N/A')}</p>"
        f"<p>Subject: {user['sub']}</p>"
        f'<p><a href="/profile">Profile</a> | <a href="/logout">Logout</a></p>'
    )


@app.route("/profile")
@login_required
def profile():
    """Show user profile information."""
    return jsonify(session["user"])


@app.route("/logout")
def logout():
    """Clear the session and log out."""
    session.clear()
    return redirect(url_for("index"))


@app.errorhandler(403)
def forbidden(e):
    return (
        f"<h2>Authentication Error</h2>"
        f"<p>{e.description}</p>"
        f'<p><a href="/login">Try logging in again</a></p>'
    ), 403


